document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("progress-container"),t=document.querySelector(".progress"),n=2*Math.PI*45;if(!e||!t)return;window.addEventListener("scroll",()=>{const s=document.documentElement.scrollHeight-window.innerHeight,o=window.pageYOffset;if(s>0){const e=o/s*n;t.style.strokeDashoffset=n-e}o>300?e.style.display="flex":e.style.display="none";const i=o>=s;e.classList.toggle("is-complete",i)}),e.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"})})})